var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふう……","ENG":"Phew...","TWN":"呼……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"괜찮나? 술을 너무 많이 마신 것 같은데.","JPN":"大丈夫か？　ちょっと飲みすぎなようだが。","ENG":"Are you okay? I think you drank too much.","TWN":"你還好嗎？你好像喝多了。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"날 너무 얕보는군. 이 정도로 쓰러지진 않아.","JPN":"そんなに甘く見るな。これくらいじゃ倒れやしない。","ENG":"You underestimate me. This isn't nearly enough to take me out.","TWN":"真是太小看我了，這種程度不算什麼。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흐음, 하지만 카운터라고 해도 꽤나 마셨는데.","JPN":"ふむ。しかしカウンターとはいえ、かなり飲んでいるぞ。","ENG":"Hmm... but you did drink a lot. Even for a Counter.","TWN":"嗯……但即使是制裁者，這樣也喝了不少。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아버지가 주량을 늘리라고 억지로 먹인 덕분이지.","JPN":"父に飲めるようになれと無理やり飲まされて鍛えられたんだ。","ENG":"My father forced me to increase my tolerance by drinking like a fish.","TWN":"這要多虧我父親為了讓我提高酒量，強迫我喝。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"<color=#ffd34c>얕잡혀 보일 구석을 남겨 두지 마라.</color> 그나마 유용한 가르침이었어.","JPN":"<color=#ffd34c>見くびられる余地を残すな。</color>割と役立つ教えだった。","ENG":"<color=#ffd34c>Don't leave any vulnerabilities they could exploit.</color> That's about the only useful thing he taught me.","TWN":"他說<color=#ffd34c>不能給敵人任何可乘之機。</color>這是個有用的教誨。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"방금 건 그저...... 한참 떠들었더니 얼마나 거지 같은 상황이었는지 떠올라서 그래.","JPN":"さっきのあれは……あの状況がどれだけ腹立たしい状況だったのか思い出したせいだよ。","ENG":"As for what just happened... It's only because all this yapping reminded me of that miserable incident.","TWN":"剛才只是……說多了，加上想起當時的情況有些生氣而已。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......왜 이제까지 잊고 있었나 이상할 만큼.","JPN":"……なぜ今まで忘れていたのか、不思議なくらいだ。","ENG":"Almost makes me wonder how I forgot all about it till now.","TWN":"……我都差點忘了。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하기야 많이 분했겠군.","JPN":"まあ、それは確かに悔しいな。","ENG":"It must have been infuriating.","TWN":"應該是很生氣吧。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"몸만 가눌 수 있었어도 그런 굴욕은 당하지 않았을 테니까.","JPN":"体さえちゃんと動かせたなら、あんな侮辱を受けなかったはずだからな。","ENG":"You wouldn't have had to endure such humiliation if you had conserved your energy.","TWN":"當時只要我稍微有點力氣，也不至於受到那樣的侮辱。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그런 건 다 핑계야.","JPN":"そんなのは全部言い訳だ。","ENG":"That's all just a sorry excuse.","TWN":"那些都是藉口。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"지금 와서 생각해 보면...... 나도 내심 바라고 있었는지도 모르지.","JPN":"今振り返ってみれば……私も内心願っていたのかもしれない。","ENG":"Looking back... maybe I was actually hoping for something like that.","TWN":"現在想想……也許那是我所希望的。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이가 나처럼 험한 꼴을 겪어 보기를 말이야.","JPN":"ガキが私みたいに散々な経験をしてほしいと。","ENG":"Maybe I wanted the kid to have a hard time like I did.","TWN":"讓那個小鬼也像我一樣經歷一下世間的兇險。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"유치한 발상이로군. 꼭 어린애들이 좋아하는 친구한테 괜히 장난치는 것 같아.","JPN":"幼稚な発想だな。まるで子どもが好きな子にいたずらをするようだ。","ENG":"How juvenile. You're like a child playing pranks on a kid you like.","TWN":"想法真是幼稚。就像小孩子一定要跟喜歡的朋友惡作劇一樣。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"동감이야.","JPN":"同感さ。","ENG":"Agreed.","TWN":"同感。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"한 번 호되게 당하면 정신을 차릴 줄 알았지.","JPN":"一度ひどい目にあえば、考えを改めると思った。","ENG":"I just figured getting her butt kicked would finally teach her a lesson.","TWN":"我以為讓她狠狠摔一跤就會打起精神。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 꼬맹이는 남을 의심하는 법이 없거든. 사람들이 다 자기처럼 착해 빠진 줄 알고 있었어.","JPN":"あのガキは他人を疑うことを知らなかったから。人がみんな自分みたいに善良だと勘違いしてた。","ENG":"The kid never found anyone suspicious, you see. She just thought everyone was as stupidly honest as she was.","TWN":"但那個孩子根本不會對別人起疑心。以為其他人都像自己一樣善良。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"혼자 내버려두면 며칠 안 가서 속옷까지 탈탈 털리고 버려질 걸.","JPN":"あいつを一人放っておけば、数日で身ぐるみをはがされ道端に捨てられるだろう。","ENG":"She'd probably get swindled down to her socks if I left her alone for a few days.","TWN":"如果放任她不管，可能自己被賣了都還在幫人家數錢呢。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};